const prompt = $.input.videoPrompt || '';
const keywords = prompt.split(' ').filter(w => w.length > 3).slice(0, 5).join(' ');
const query = 'AI video generation techniques ' + keywords + ' cinematic style';
return { query };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Video Production Brief', optimizedPrompt: raw }; }

const ai = $.steps.parseAI.output;
let doc = 'VIDEO PRODUCTION BRIEF
';
doc += '=====================

';
doc += 'Title: ' + (ai.title || 'Untitled') + '
';
doc += 'Date: ' + new Date().toISOString().split('T')[0] + '
';
doc += 'Original Prompt: ' + $.input.videoPrompt + '

';
doc += 'OPTIMIZED PROMPT
';
doc += '----------------
';
doc += (ai.optimizedPrompt || '') + '

';
doc += 'SPECIFICATIONS
';
doc += '--------------
';
doc += 'Duration: ' + (ai.duration || 'N/A') + '
';
doc += 'Aspect Ratio: ' + (ai.aspectRatio || '16:9') + '
';
doc += 'Style: ' + (ai.style || 'N/A') + '
';
doc += 'Mood: ' + (ai.mood || 'N/A') + '
';
doc += 'Soundtrack: ' + (ai.soundtrack || 'N/A') + '

';
if (ai.colorPalette) { doc += 'Color Palette: ' + ai.colorPalette.join(', ') + '
'; }
if (ai.cameraWork) { doc += 'Camera Work: ' + ai.cameraWork.join(', ') + '
'; }
doc += '
SCENES
';
doc += '------
';
if (ai.scenes) { ai.scenes.forEach(s => { doc += s.sceneNumber + '. ' + s.description + ' (' + s.duration + ', ' + s.transition + ')
'; }); }
if (ai.technicalNotes) { doc += '
TECHNICAL NOTES
'; ai.technicalNotes.forEach(n => { doc += '- ' + n + '
'; }); }
return { doc, title: ai.title || 'Video Brief', slackText: 'Video production brief ready: ' + (ai.title || 'Untitled') + ' | ' + (ai.duration || '') + ' | ' + (ai.style || '') };
